import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface GoalProgress {
  stage: string;
  amount: number;
}

interface CampaignData {
  campaign: {
    name: string;
    totalRaised: number;
    goal: number;
    donorCount: number;
  };
  goalProgress: GoalProgress[];
}

export default function Widget() {
  const campaignData = response.data as CampaignData;
  const { campaign, goalProgress } = campaignData;
  const progressPercentage = (campaign.totalRaised / campaign.goal) * 100;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2.5}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              {campaign.name}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              ${campaign.totalRaised.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              raised of ${campaign.goal.toLocaleString()} goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#FF5722' }}>
                {progressPercentage.toFixed(2)}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={progressPercentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#FFE0B2',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FF5722',
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: goalProgress.map(g => g.amount),
                color: '#FFC107',
              },
            ]}
            xAxis={[
              {
                data: goalProgress.map(g => g.stage),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
